#!/usr/bin/env node
/**
 * Verify that every URL generated by `specUrl()` resolves to:
 *   1. an HTTP 200 page, AND
 *   2. an anchor (`id="…"`) that actually exists in that page's HTML.
 *
 * The Atlassian docs site is a single-page-app per group, so a 200 status
 * proves only that the group page exists — the per-endpoint anchor is what
 * actually jumps you to the right section. If the anchor is missing, the link
 * lands at the top of the group page instead of the endpoint.
 *
 * Group pages are fetched once, cached in-memory, then every endpoint anchor
 * is checked against the cached HTML. ~95 endpoints across ~11 group pages
 * means ~11 network calls.
 */
import { TOOL_ENDPOINTS, specUrl } from "../dist/tools/_spec-links.js";

const pageCache = new Map(); // groupUrl → { status, html }

async function fetchPage(groupUrl) {
  if (pageCache.has(groupUrl)) return pageCache.get(groupUrl);
  const res = await fetch(groupUrl, { redirect: "follow" });
  const html = await res.text();
  const out = { status: res.status, html };
  pageCache.set(groupUrl, out);
  return out;
}

const results = [];
const names = Object.keys(TOOL_ENDPOINTS).sort();

for (const name of names) {
  const ep = TOOL_ENDPOINTS[name];
  const fullUrl = specUrl(ep.method, ep.path);
  const [groupUrl, anchor] = fullUrl.split("#");
  const { status, html } = await fetchPage(groupUrl);
  // Anchors typically appear as `id="..."` (and sometimes nested in elements
  // like `id="api-..."`). Look for the literal id attribute value.
  const anchorRe = new RegExp(`id=["']${anchor.replace(/[.*+?^${}()|[\]\\]/g, "\\$&")}["']`);
  const anchorOk = anchorRe.test(html);
  results.push({
    name,
    method: ep.method,
    path: ep.path,
    url: fullUrl,
    groupStatus: status,
    anchorOk,
  });
}

// ── Report ──────────────────────────────────────────────────────────────────
const ok = results.filter((r) => r.groupStatus === 200 && r.anchorOk);
const noPage = results.filter((r) => r.groupStatus !== 200);
const noAnchor = results.filter((r) => r.groupStatus === 200 && !r.anchorOk);

console.log(`\n=== Spec URL verification (${results.length} endpoints) ===\n`);
console.log(`  ✓ ${ok.length} fully verified (page 200 + anchor present)`);
console.log(`  ✗ ${noPage.length} group page returned non-200`);
console.log(`  ⚠ ${noAnchor.length} page exists but anchor not found\n`);

if (noPage.length) {
  console.log("=== group-page failures ===");
  for (const r of noPage) console.log(`  ${r.groupStatus}  ${r.name.padEnd(40)} → ${r.url}`);
  console.log();
}
if (noAnchor.length) {
  console.log("=== anchor not found (page exists, but #fragment doesn't match any id) ===");
  for (const r of noAnchor) console.log(`  ${r.name.padEnd(40)} → ${r.url}`);
  console.log();
}

console.log("=== group-page cache stats ===");
for (const [g, { status, html }] of pageCache.entries()) {
  console.log(`  ${status}  ${(html.length / 1024).toFixed(1).padStart(7)} KB  ${g}`);
}

process.exit(noPage.length + noAnchor.length > 0 ? 1 : 0);
